struct Cache : Cacheable {
    float* x0 = nullptr;
    float* x1 = nullptr;
    float* d_scalar = nullptr;
    int32_t x0_capacity = 0;
    int32_t x1_capacity = 0;
    bool scalar_allocated = false;

    void ensure(int32_t n) {
        if (x0_capacity < n) {
            if (x0) cudaFree(x0);
            cudaMalloc(&x0, (size_t)n * sizeof(float));
            x0_capacity = n;
