            deg += w2;
            intra += ((int32_t)__ldg(&cluster_assignments[n2]) == c_v) ? w2 : 0.0f;

            float w3 = __ldg(&edge_weights[e + 3]);
            int32_t n3 = __ldg(&indices[e + 3]);
            deg += w3;
            intra += ((int32_t)__ldg(&cluster_assignments[n3]) == c_v) ? w3 : 0.0f;
