    int*d_oa=pool.al<int>(nv+1);int*d_ia=pool.al<int>(ne);float*d_wa=pool.al<float>(ne);
    int*d_ob=pool.al<int>(nv+1);int*d_ib=pool.al<int>(ne);float*d_wb=pool.al<float>(ne);

