}  

ecg_result_float_t ecg(const graph32_t& graph,
                       const float* edge_weights,
                       int32_t* clusters,
                       float min_weight,
                       std::size_t ensemble_size,
                       std::size_t max_level,
                       float threshold,
                       float resolution) {
    static int tag;
    auto& cache = cache_pool().acquire<Cache>(&tag);

    int32_t nv = graph.number_of_vertices;
    int32_t ne = graph.number_of_edges;

    cache.ensure(nv, ne);

    return ecg_run_impl(
        graph.offsets, graph.indices, edge_weights,
        nv, ne, min_weight, (int)ensemble_size, (int)max_level, threshold, resolution,
        clusters,
        cache.scratch, cache.scratch_size);
}

