#define HM_SIZE 32
#define HM_MASK (HM_SIZE - 1)



template <typename T>
void ensure_buf(T*& ptr, int64_t& cap, int64_t need) {
    if (cap < need) {
        if (ptr) cudaFree(ptr);
        cudaMalloc(&ptr, need * sizeof(T));
        cap = need;
    }
}

