__device__ bool seq_process_vertex(
    int v,
    const int32_t* __restrict__ offsets,
    const int32_t* __restrict__ indices,
    const float* __restrict__ edge_weights,
    int32_t* __restrict__ community,
    float* __restrict__ sigma_tot,
    const float* __restrict__ vertex_weight,
    float total_weight, float resolution,
    int* hash_keys, float* hash_vals
) {
    int start = offsets[v];
    int end = offsets[v + 1];
    if (start == end) return false;

    int my_comm = community[v];
    double my_k = (double)vertex_weight[v];


    for (int i = 0; i < SEQ_HASH_CAP; i++) {
        hash_keys[i] = -1;
        hash_vals[i] = 0.0f;
    }


    for (int e = start; e < end; e++) {
        if (indices[e] == v) continue;
        int c = community[indices[e]];
        float w = edge_weights[e];
        unsigned int slot = ((unsigned int)c * 2654435761u) % (unsigned int)SEQ_HASH_CAP;
        for (int p = 0; p < SEQ_HASH_CAP; p++) {
            int pos = ((int)slot + p) % SEQ_HASH_CAP;
            if (hash_keys[pos] == c) { hash_vals[pos] += w; break; }
            else if (hash_keys[pos] == -1) { hash_keys[pos] = c; hash_vals[pos] = w; break; }
        }
    }


    double k_own = 0.0;
    for (int i = 0; i < SEQ_HASH_CAP; i++) {
        if (hash_keys[i] == my_comm) { k_own = (double)hash_vals[i]; break; }
    }

    double sigma_own = (double)sigma_tot[my_comm];
    double tw_d = (double)total_weight;
    double res_d = (double)resolution;
    double base_score = k_own - res_d * my_k * (sigma_own - my_k) / tw_d;
    double best_score = base_score;
    int best_comm = my_comm;

    for (int i = 0; i < SEQ_HASH_CAP; i++) {
        int c = hash_keys[i];
        if (c == -1 || c == my_comm) continue;
        double score = (double)hash_vals[i] - res_d * my_k * (double)sigma_tot[c] / tw_d;
        if (score > best_score || (score == best_score && c < best_comm && score > base_score)) {
            best_score = score;
            best_comm = c;
        }
    }

    if (best_comm != my_comm) {
        sigma_tot[my_comm] -= vertex_weight[v];
        sigma_tot[best_comm] += vertex_weight[v];
        community[v] = best_comm;
        return true;
    }
    return false;
}



__global__ void init_communities_kernel(int32_t* __restrict__ community, int N) {
    int v = blockIdx.x * blockDim.x + threadIdx.x;
    if (v >= N) return;
    community[v] = v;
}

__global__ void compute_vertex_weights_kernel(
    const int32_t* __restrict__ offsets, const float* __restrict__ edge_weights,
    float* __restrict__ vertex_weights, int num_vertices) {
    int v = blockIdx.x * blockDim.x + threadIdx.x;
    if (v >= num_vertices) return;
    float w = 0.0f;
    for (int e = offsets[v]; e < offsets[v + 1]; e++) w += edge_weights[e];
    vertex_weights[v] = w;
}

__global__ void reduce_sum_kernel(const float* __restrict__ input, float* __restrict__ output, int N) {
    __shared__ float sdata[BLOCK_SIZE];
    int tid = threadIdx.x;
    float sum = 0.0f;
    for (int i = blockIdx.x * blockDim.x + tid; i < N; i += gridDim.x * blockDim.x)
        sum += input[i];
    sdata[tid] = sum;
    __syncthreads();
    for (int s = BLOCK_SIZE / 2; s > 0; s >>= 1) {
        if (tid < s) sdata[tid] += sdata[tid + s];
        __syncthreads();
    }
    if (tid == 0) atomicAdd(output, sdata[0]);
}

__global__ void recompute_sigma_tot_kernel(const int32_t* __restrict__ community,
    const float* __restrict__ vw, float* __restrict__ sigma_tot, int N) {
    int v = blockIdx.x * blockDim.x + threadIdx.x;
    if (v < N) atomicAdd(&sigma_tot[community[v]], vw[v]);
}

__global__ void local_move_kernel(
    const int32_t* __restrict__ offsets, const int32_t* __restrict__ indices,
    const float* __restrict__ edge_weights, int32_t* __restrict__ community,
    const float* __restrict__ sigma_tot, const float* __restrict__ vertex_weight,
    int N, float total_weight, float resolution, int* __restrict__ changed,
    int color, int num_colors)
{
    extern __shared__ char smem[];
    int* s_keys = (int*)smem;
    float* s_vals = (float*)(smem + blockDim.x * HASH_CAP * sizeof(int));

    int tid = threadIdx.x;
    int idx = blockIdx.x * blockDim.x + tid;
    int v = idx * num_colors + color;

    int base = tid * HASH_CAP;
    for (int i = 0; i < HASH_CAP; i++) {
        s_keys[base + i] = -1;
        s_vals[base + i] = 0.0f;
    }

    if (v >= N) return;

    int my_comm = community[v];
    float my_k = vertex_weight[v];
    int start = offsets[v];
    int end = offsets[v + 1];
    if (start == end) return;

    for (int e = start; e < end; e++) {
        if (indices[e] == v) continue;  
        int c = community[indices[e]];
        float w = edge_weights[e];
        unsigned int slot = ((unsigned int)c * 2654435761u) % (unsigned int)HASH_CAP;
        for (int p = 0; p < HASH_CAP; p++) {
            int pos = base + ((int)(slot + p) % HASH_CAP);
            if (s_keys[pos] == c) { s_vals[pos] += w; break; }
            else if (s_keys[pos] == -1) { s_keys[pos] = c; s_vals[pos] = w; break; }
        }
    }

    float k_own = 0.0f;
    for (int i = 0; i < HASH_CAP; i++) {
        if (s_keys[base + i] == my_comm) { k_own = s_vals[base + i]; break; }
    }

    float sigma_own = sigma_tot[my_comm];
    float base_score = k_own - resolution * my_k * (sigma_own - my_k) / total_weight;
    float best_score = base_score;
    int best_comm = my_comm;

    for (int i = 0; i < HASH_CAP; i++) {
        int c = s_keys[base + i];
        if (c == -1 || c == my_comm) continue;
        float score = s_vals[base + i] - resolution * my_k * sigma_tot[c] / total_weight;
        if (score > best_score) { best_score = score; best_comm = c; }
    }

    if (best_comm != my_comm) {
        community[v] = best_comm;
        *changed = 1;
    }
}

__global__ void compute_best_move_kernel(
    const int32_t* __restrict__ offsets, const int32_t* __restrict__ indices,
    const float* __restrict__ edge_weights, const int32_t* __restrict__ community,
    const float* __restrict__ sigma_tot, const float* __restrict__ vertex_weight,
    int N, float total_weight, float resolution,
    int32_t* __restrict__ best_comm_out, float* __restrict__ best_gain_out)
{
    extern __shared__ char smem[];
    int* s_keys = (int*)smem;
    float* s_vals = (float*)(smem + blockDim.x * HASH_CAP * sizeof(int));

    int tid = threadIdx.x;
    int v = blockIdx.x * blockDim.x + tid;

    int base = tid * HASH_CAP;
    for (int i = 0; i < HASH_CAP; i++) {
        s_keys[base + i] = -1;
        s_vals[base + i] = 0.0f;
    }

    if (v >= N) return;

    int my_comm = community[v];
    float my_k = vertex_weight[v];
    int start = offsets[v];
    int end = offsets[v + 1];

    if (start == end) {
        best_comm_out[v] = my_comm;
        best_gain_out[v] = 0.0f;
        return;
    }

    for (int e = start; e < end; e++) {
        if (indices[e] == v) continue;  
        int c = community[indices[e]];
        float w = edge_weights[e];
        unsigned int slot = ((unsigned int)c * 2654435761u) % (unsigned int)HASH_CAP;
        for (int p = 0; p < HASH_CAP; p++) {
            int pos = base + ((int)(slot + p) % HASH_CAP);
            if (s_keys[pos] == c) { s_vals[pos] += w; break; }
            else if (s_keys[pos] == -1) { s_keys[pos] = c; s_vals[pos] = w; break; }
        }
    }

    float k_own = 0.0f;
    for (int i = 0; i < HASH_CAP; i++) {
        if (s_keys[base + i] == my_comm) { k_own = s_vals[base + i]; break; }
    }

    float sigma_own = sigma_tot[my_comm];
    float base_score = k_own - resolution * my_k * (sigma_own - my_k) / total_weight;
    float best_score = 0.0f;  
    int best_c = my_comm;

    for (int i = 0; i < HASH_CAP; i++) {
        int c = s_keys[base + i];
        if (c == -1 || c == my_comm) continue;
        float score = s_vals[base + i] - resolution * my_k * sigma_tot[c] / total_weight;
        float delta = score - base_score;
        if (delta > best_score || (delta == best_score && delta > 0.0f && c < best_c)) {
            best_score = delta;
            best_c = c;
        }
    }

    best_comm_out[v] = best_c;
    best_gain_out[v] = best_score;
}

__global__ void count_updown_kernel(
    const int32_t* __restrict__ community, const int32_t* __restrict__ best_comm,
    const float* __restrict__ best_gain, int N, bool up_down, int* __restrict__ count)
{
    int v = blockIdx.x * blockDim.x + threadIdx.x;
    if (v >= N) return;
    if (best_gain[v] > 0.0f) {
        bool is_up = best_comm[v] > community[v];
        if (is_up == up_down) atomicAdd(count, 1);
    }
}

__global__ void apply_updown_kernel(
    int32_t* __restrict__ community, const int32_t* __restrict__ best_comm,
    const float* __restrict__ best_gain, int N, bool up_down)
{
    int v = blockIdx.x * blockDim.x + threadIdx.x;
    if (v >= N) return;
    if (best_gain[v] > 0.0f) {
        bool is_up = best_comm[v] > community[v];
        if (is_up == up_down) {
            community[v] = best_comm[v];
        }
    }
}

__global__ void sequential_local_move_kernel(
    const int32_t* __restrict__ offsets, const int32_t* __restrict__ indices,
    const float* __restrict__ weights, int32_t* __restrict__ community,
    float* __restrict__ sigma_tot, const float* __restrict__ vw,
    int N, float tw, float res, int* __restrict__ changed, int start_offset)
{
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    int hash_keys[SEQ_HASH_CAP];
    float hash_vals[SEQ_HASH_CAP];

    for (int i = 0; i < N; i++) {
        int v = (i + start_offset) % N;
        if (seq_process_vertex(v, offsets, indices, weights, community,
                               sigma_tot, vw, tw, res, hash_keys, hash_vals))
            *changed = 1;
    }
}

__global__ void batch_sequential_louvain_kernel(
    const int32_t* __restrict__ offsets,
    const int32_t* __restrict__ indices,
    const float* __restrict__ edge_weights,
    const float* __restrict__ vertex_weight,
    int N, float total_weight, float resolution,
    int32_t* __restrict__ all_communities,
    float* __restrict__ all_sigma,
    float* __restrict__ all_modularity,
    int num_restarts)
{
    int restart = blockIdx.x;
    if (restart >= num_restarts || threadIdx.x != 0) return;

    int32_t* comm = all_communities + restart * N;
    float* sigma = all_sigma + restart * N;

    int perm[BATCH_MAX_N];
    for (int i = 0; i < N; i++) perm[i] = i;

    if (restart == 1) {
        for (int i = 0; i < N / 2; i++) {
            int tmp = perm[i]; perm[i] = perm[N-1-i]; perm[N-1-i] = tmp;
        }
    } else if (restart >= 2) {
        unsigned long long seed = (unsigned long long)restart * 6364136223846793005ULL + 1442695040888963407ULL;
        for (int i = N - 1; i > 0; i--) {
            seed = seed * 6364136223846793005ULL + 1442695040888963407ULL;
            int j = (int)((seed >> 16) % (unsigned long long)(i + 1));
            int tmp = perm[i]; perm[i] = perm[j]; perm[j] = tmp;
        }
    }

    for (int i = 0; i < N; i++) comm[i] = i;

    int hash_keys[SEQ_HASH_CAP];
    float hash_vals[SEQ_HASH_CAP];

    for (int iter = 0; iter < 200; iter++) {
        for (int i = 0; i < N; i++) sigma[i] = 0.0f;
        for (int i = 0; i < N; i++) sigma[comm[i]] += vertex_weight[i];

        bool changed = false;
        for (int i = 0; i < N; i++) {
            int v = perm[i];
            if (seq_process_vertex(v, offsets, indices, edge_weights,
                                   comm, sigma, vertex_weight,
                                   total_weight, resolution,
                                   hash_keys, hash_vals))
                changed = true;
        }
        for (int i = N - 1; i >= 0; i--) {
            int v = perm[i];
            if (seq_process_vertex(v, offsets, indices, edge_weights,
                                   comm, sigma, vertex_weight,
                                   total_weight, resolution,
                                   hash_keys, hash_vals))
                changed = true;
        }
        if (!changed) break;
    }

    for (int i = 0; i < N; i++) sigma[i] = 0.0f;
    for (int i = 0; i < N; i++) sigma[comm[i]] += vertex_weight[i];

    double iw = 0.0;
    for (int v = 0; v < N; v++) {
        int cv = comm[v];
        for (int e = offsets[v]; e < offsets[v + 1]; e++) {
            if (comm[indices[e]] == cv) iw += (double)edge_weights[e];
        }
    }
    double ssq = 0.0;
    for (int i = 0; i < N; i++) {
        double s = (double)sigma[i];
        ssq += s * s;
    }
    double m = (double)total_weight / 2.0;
    all_modularity[restart] = (float)(iw / (2.0 * m) - (double)resolution * ssq / (4.0 * m * m));
}

__global__ void mark_communities_kernel(const int32_t* __restrict__ community,
    int* __restrict__ used, int N) {
    int v = blockIdx.x * blockDim.x + threadIdx.x;
    if (v < N) used[community[v]] = 1;
}

__global__ void apply_renumber_kernel(int32_t* __restrict__ community,
    const int* __restrict__ prefix, int N) {
    int v = blockIdx.x * blockDim.x + threadIdx.x;
    if (v < N) community[v] = prefix[community[v]];
}

__global__ void map_edges_kernel(const int32_t* __restrict__ offsets,
    const int32_t* __restrict__ indices, const int32_t* __restrict__ community,
    int64_t* __restrict__ edge_keys, int N) {
    int v = blockIdx.x * blockDim.x + threadIdx.x;
    if (v >= N) return;
    int cv = community[v];
    for (int e = offsets[v]; e < offsets[v + 1]; e++) {
        int cu = community[indices[e]];
        edge_keys[e] = ((int64_t)(unsigned int)cv << 32) | (int64_t)(unsigned int)cu;
    }
}

__global__ void count_src_edges_kernel(const int64_t* __restrict__ keys,
    int* __restrict__ counts, int ne) {
    int e = blockIdx.x * blockDim.x + threadIdx.x;
    if (e < ne) atomicAdd(&counts[(int)(keys[e] >> 32)], 1);
}

__global__ void fill_csr_kernel(const int64_t* __restrict__ keys,
    const float* __restrict__ vals, const int* __restrict__ offsets,
    int32_t* __restrict__ indices, float* __restrict__ weights, int ne) {
    int e = blockIdx.x * blockDim.x + threadIdx.x;
    if (e < ne) {
        indices[e] = (int32_t)(keys[e] & 0xFFFFFFFF);
        weights[e] = vals[e];
    }
}

__global__ void compute_new_vw_kernel(const float* __restrict__ old_vw,
    const int32_t* __restrict__ community, float* __restrict__ new_vw, int old_N) {
    int v = blockIdx.x * blockDim.x + threadIdx.x;
    if (v < old_N) atomicAdd(&new_vw[community[v]], old_vw[v]);
}

__global__ void compose_communities_kernel(int32_t* __restrict__ final_comm,
    const int32_t* __restrict__ level_comm, int N) {
    int v = blockIdx.x * blockDim.x + threadIdx.x;
    if (v < N) final_comm[v] = level_comm[final_comm[v]];
}

__global__ void compute_iw_kernel(
    const int32_t* __restrict__ off, const int32_t* __restrict__ idx,
    const float* __restrict__ w, const int32_t* __restrict__ c,
    int N, double* __restrict__ result) {
    typedef cub::BlockReduce<double, BLOCK_SIZE> BR;
    __shared__ typename BR::TempStorage tmp;
    double s = 0.0;
    for (int v = blockIdx.x * blockDim.x + threadIdx.x; v < N; v += blockDim.x * gridDim.x) {
        int cv = c[v];
        for (int e = off[v]; e < off[v + 1]; e++)
            if (c[idx[e]] == cv) s += (double)w[e];
    }
    double bs = BR(tmp).Sum(s);
    if (threadIdx.x == 0) atomicAdd(result, bs);
}

__global__ void compute_ssq_kernel(
    const float* __restrict__ st, int N, double* __restrict__ result) {
    typedef cub::BlockReduce<double, BLOCK_SIZE> BR;
    __shared__ typename BR::TempStorage tmp;
    double s = 0.0;
    for (int i = blockIdx.x * blockDim.x + threadIdx.x; i < N; i += blockDim.x * gridDim.x) {
        double v = (double)st[i]; s += v * v;
    }
    double bs = BR(tmp).Sum(s);
    if (threadIdx.x == 0) atomicAdd(result, bs);
}



static float compute_modularity(Cache& cache,
    const int32_t* offsets, const int32_t* indices, const float* weights,
    const int32_t* clusters, const float* vw, int N, float total_weight, float resolution) {
    cache.ensure_mod(N);
    float* sigma = cache.mod_sigma;
    double* d_accum = cache.mod_accum;

    cudaMemset(sigma, 0, N * sizeof(float));
    recompute_sigma_tot_kernel<<<(N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(clusters, vw, sigma, N);

    cudaMemset(d_accum, 0, sizeof(double));
    int g = (N + BLOCK_SIZE - 1) / BLOCK_SIZE;
    if (g > 1024) g = 1024;
    compute_iw_kernel<<<g, BLOCK_SIZE>>>(offsets, indices, weights, clusters, N, d_accum);
    double iw;
    cudaMemcpy(&iw, d_accum, sizeof(double), cudaMemcpyDeviceToHost);

    cudaMemset(d_accum, 0, sizeof(double));
    compute_ssq_kernel<<<g, BLOCK_SIZE>>>(sigma, N, d_accum);
    double ssq;
    cudaMemcpy(&ssq, d_accum, sizeof(double), cudaMemcpyDeviceToHost);

    double m = (double)total_weight / 2.0;
    return (float)(iw / (2.0 * m) - (double)resolution * ssq / (4.0 * m * m));
}

static int renumber_communities(Cache& cache, int32_t* community, int* used, int* prefix, int N) {
    int grid = (N + BLOCK_SIZE - 1) / BLOCK_SIZE;
    cudaMemset(used, 0, N * sizeof(int));
    mark_communities_kernel<<<grid, BLOCK_SIZE>>>(community, used, N);

    size_t temp_bytes = 0;
    cub::DeviceScan::ExclusiveSum(nullptr, temp_bytes, used, prefix, N);
    cache.ensure_cub(temp_bytes);
    cub::DeviceScan::ExclusiveSum(cache.cub_temp, temp_bytes, used, prefix, N);

    int h_last_prefix, h_last_used;
    cudaMemcpy(&h_last_prefix, prefix + N - 1, sizeof(int), cudaMemcpyDeviceToHost);
    cudaMemcpy(&h_last_used, used + N - 1, sizeof(int), cudaMemcpyDeviceToHost);
    int new_N = h_last_prefix + h_last_used;

    apply_renumber_kernel<<<grid, BLOCK_SIZE>>>(community, prefix, N);
    return new_N;
}

static int sort_reduce_edges(Cache& cache,
    int64_t* keys_in, float* vals_in, int E,
    int64_t* sort_keys_out, float* sort_vals_out,
    int64_t* unique_keys_out, float* unique_vals_out, int* d_num_unique) {

    size_t sort_temp = 0;
    cub::DeviceRadixSort::SortPairs(nullptr, sort_temp, keys_in, sort_keys_out, vals_in, sort_vals_out, E);
    cache.ensure_cub(sort_temp);
    cub::DeviceRadixSort::SortPairs(cache.cub_temp, sort_temp, keys_in, sort_keys_out, vals_in, sort_vals_out, E);

    size_t reduce_temp = 0;
    cub::DeviceReduce::ReduceByKey(nullptr, reduce_temp, sort_keys_out, unique_keys_out,
        sort_vals_out, unique_vals_out, d_num_unique, ::cuda::std::plus<float>{}, E);
    cache.ensure_cub(reduce_temp);
    cub::DeviceReduce::ReduceByKey(cache.cub_temp, reduce_temp, sort_keys_out, unique_keys_out,
        sort_vals_out, unique_vals_out, d_num_unique, ::cuda::std::plus<float>{}, E);

    int h_num_unique;
    cudaMemcpy(&h_num_unique, d_num_unique, sizeof(int), cudaMemcpyDeviceToHost);
    return h_num_unique;
}

static void build_csr_from_keys(Cache& cache,
    const int64_t* unique_keys, const float* unique_vals,
    int new_E, int new_N,
    int* counts, int32_t* new_offsets, int32_t* new_indices, float* new_weights) {

    int grid_e = (new_E + BLOCK_SIZE - 1) / BLOCK_SIZE;

    cudaMemset(counts, 0, new_N * sizeof(int));
    count_src_edges_kernel<<<grid_e, BLOCK_SIZE>>>(unique_keys, counts, new_E);

    size_t temp_bytes = 0;
    cub::DeviceScan::ExclusiveSum(nullptr, temp_bytes, counts, (int*)new_offsets, new_N + 1);
    cache.ensure_cub(temp_bytes);
    cub::DeviceScan::ExclusiveSum(cache.cub_temp, temp_bytes, counts, (int*)new_offsets, new_N);

    int h_new_E = new_E;
    cudaMemcpy(new_offsets + new_N, &h_new_E, sizeof(int32_t), cudaMemcpyHostToDevice);

    fill_csr_kernel<<<grid_e, BLOCK_SIZE>>>(unique_keys, unique_vals, (int*)new_offsets, new_indices, new_weights, new_E);
}



static int coarsen_graph(Cache& cache,
    const int32_t* cur_off, const int32_t* cur_idx, const float* cur_wt,
    const float* cur_vw, int32_t* community, int cur_N, int cur_E, int new_N,
    int32_t** out_off, int32_t** out_idx, float** out_wt, float** out_vw) {

    int64_t* ek; cudaMalloc(&ek, cur_E * sizeof(int64_t));
    float* ev; cudaMalloc(&ev, cur_E * sizeof(float));
    map_edges_kernel<<<(cur_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(
        cur_off, cur_idx, community, ek, cur_N);
    cudaMemcpy(ev, cur_wt, cur_E * sizeof(float), cudaMemcpyDeviceToDevice);

    int64_t* sk; cudaMalloc(&sk, cur_E * sizeof(int64_t));
    float* sv; cudaMalloc(&sv, cur_E * sizeof(float));
    int64_t* uk; cudaMalloc(&uk, cur_E * sizeof(int64_t));
    float* uv; cudaMalloc(&uv, cur_E * sizeof(float));
    int* nu; cudaMalloc(&nu, sizeof(int));

    int new_E = sort_reduce_edges(cache, ek, ev, cur_E, sk, sv, uk, uv, nu);

    cudaMalloc(out_off, (new_N + 1) * sizeof(int32_t));
    cudaMalloc(out_idx, new_E * sizeof(int32_t));
    cudaMalloc(out_wt, new_E * sizeof(float));
    int* cnt; cudaMalloc(&cnt, new_N * sizeof(int));
    build_csr_from_keys(cache, uk, uv, new_E, new_N, cnt, *out_off, *out_idx, *out_wt);

    cudaMalloc(out_vw, new_N * sizeof(float));
    cudaMemset(*out_vw, 0, new_N * sizeof(float));
    compute_new_vw_kernel<<<(cur_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(
        cur_vw, community, *out_vw, cur_N);

    cudaFree(ek); cudaFree(ev);
    cudaFree(sk); cudaFree(sv);
    cudaFree(uk); cudaFree(uv);
    cudaFree(nu); cudaFree(cnt);

    return new_E;
}

}  

louvain_result_float_t louvain_seg(const graph32_t& graph,
                                   const float* edge_weights,
                                   int32_t* clusters,
                                   std::size_t max_level,
                                   float threshold,
                                   float resolution) {
    static int tag;
    auto& cache = cache_pool().acquire<Cache>(&tag);

    const int32_t* offsets = graph.offsets;
    const int32_t* indices = graph.indices;
    int32_t orig_N = graph.number_of_vertices;
    int32_t orig_E = graph.number_of_edges;


    float* orig_vw;
    cudaMalloc(&orig_vw, orig_N * sizeof(float));
    compute_vertex_weights_kernel<<<(orig_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(
        offsets, edge_weights, orig_vw, orig_N);


    float* d_tw;
    cudaMalloc(&d_tw, sizeof(float));
    cudaMemset(d_tw, 0, sizeof(float));
    { int rg = (orig_N + BLOCK_SIZE - 1) / BLOCK_SIZE; if (rg > 1024) rg = 1024;
      reduce_sum_kernel<<<rg, BLOCK_SIZE>>>(orig_vw, d_tw, orig_N); }
    float total_weight;
    cudaMemcpy(&total_weight, d_tw, sizeof(float), cudaMemcpyDeviceToHost);
    cudaFree(d_tw);


    init_communities_kernel<<<(orig_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(clusters, orig_N);

    if (total_weight == 0.0f || orig_N <= 1) {
        cudaFree(orig_vw);
        return louvain_result_float_t{0, 0.0f};
    }


    int* d_count;
    cudaMalloc(&d_count, sizeof(int));

    float overall_best_Q = -1.0f;
    int64_t actual_level_count = 1;


    if (orig_N <= 256) {
        int num_restarts = 2048;
        int32_t* all_comm; cudaMalloc(&all_comm, (int64_t)num_restarts * orig_N * sizeof(int32_t));
        float* all_sigma; cudaMalloc(&all_sigma, (int64_t)num_restarts * orig_N * sizeof(float));
        float* all_mod; cudaMalloc(&all_mod, num_restarts * sizeof(float));

        batch_sequential_louvain_kernel<<<num_restarts, 1>>>(
            offsets, indices, edge_weights, orig_vw,
            orig_N, total_weight, resolution,
            all_comm, all_sigma, all_mod, num_restarts);
        cudaDeviceSynchronize();

        std::vector<float> h_mod(num_restarts);
        cudaMemcpy(h_mod.data(), all_mod, num_restarts * sizeof(float), cudaMemcpyDeviceToHost);

        std::vector<int> sorted_idx(num_restarts);
        for (int i = 0; i < num_restarts; i++) sorted_idx[i] = i;
        std::sort(sorted_idx.begin(), sorted_idx.end(),
                  [&](int a, int b) { return h_mod[a] > h_mod[b]; });

        int topK = std::min(50, num_restarts);
        int32_t* trial_comm; cudaMalloc(&trial_comm, orig_N * sizeof(int32_t));
        int* d_lc; cudaMalloc(&d_lc, sizeof(int));

        for (int ki = 0; ki < topK; ki++) {
            int idx = sorted_idx[ki];
            cudaMemcpy(trial_comm, all_comm + (int64_t)idx * orig_N,
                       orig_N * sizeof(int32_t), cudaMemcpyDeviceToDevice);

            int32_t* ml_comm; cudaMalloc(&ml_comm, orig_N * sizeof(int32_t));
            cudaMemcpy(ml_comm, trial_comm, orig_N * sizeof(int32_t), cudaMemcpyDeviceToDevice);

            int cur_N = orig_N, cur_E = orig_E;
            const int32_t* cur_off = offsets;
            const int32_t* cur_idx2 = indices;
            const float* cur_wt = edge_weights;
            const float* cur_vw2 = orig_vw;
            int32_t* c_off2 = nullptr; int32_t* c_idx2_owned = nullptr;
            float* c_wt2 = nullptr; float* c_vw2 = nullptr;
            float level_best = h_mod[idx];
            bool first_level = true;

            for (int level = 0; level < (int)max_level; level++) {
                int* used; cudaMalloc(&used, cur_N * sizeof(int));
                int* pref; cudaMalloc(&pref, cur_N * sizeof(int));
                int new_N = renumber_communities(cache, ml_comm, used, pref, cur_N);
                cudaFree(used); cudaFree(pref);

                if (new_N >= cur_N) break;

                if (first_level) {
                    cudaMemcpy(trial_comm, ml_comm, orig_N * sizeof(int32_t), cudaMemcpyDeviceToDevice);
                    first_level = false;
                } else {
                    compose_communities_kernel<<<(orig_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(
                        trial_comm, ml_comm, orig_N);
                }


                int32_t* old_c_off2 = c_off2;
                int32_t* old_c_idx2 = c_idx2_owned;
                float* old_c_wt2 = c_wt2;
                float* old_c_vw2 = c_vw2;

                int new_E = coarsen_graph(cache, cur_off, cur_idx2, cur_wt, cur_vw2,
                    ml_comm, cur_N, cur_E, new_N,
                    &c_off2, &c_idx2_owned, &c_wt2, &c_vw2);


                if (old_c_off2) cudaFree(old_c_off2);
                if (old_c_idx2) cudaFree(old_c_idx2);
                if (old_c_wt2) cudaFree(old_c_wt2);
                if (old_c_vw2) cudaFree(old_c_vw2);

                cur_N = new_N; cur_E = new_E;
                cur_off = c_off2;
                cur_idx2 = c_idx2_owned;
                cur_wt = c_wt2;
                cur_vw2 = c_vw2;


                cudaFree(ml_comm);
                cudaMalloc(&ml_comm, cur_N * sizeof(int32_t));
                init_communities_kernel<<<(cur_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(ml_comm, cur_N);

                float* ls; cudaMalloc(&ls, cur_N * sizeof(float));
                for (int iter = 0; iter < 200; iter++) {
                    cudaMemset(ls, 0, cur_N * sizeof(float));
                    recompute_sigma_tot_kernel<<<(cur_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(
                        ml_comm, cur_vw2, ls, cur_N);
                    cudaMemset(d_lc, 0, sizeof(int));
                    sequential_local_move_kernel<<<1, 1>>>(
                        cur_off, cur_idx2, cur_wt, ml_comm, ls, cur_vw2,
                        cur_N, total_weight, resolution, d_lc, 0);
                    int h_changed = 0;
                    cudaMemcpy(&h_changed, d_lc, sizeof(int), cudaMemcpyDeviceToHost);
                    if (!h_changed) break;
                }
                cudaFree(ls);

                compose_communities_kernel<<<(orig_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(
                    trial_comm, ml_comm, orig_N);
                float new_Q = compute_modularity(cache, offsets, indices, edge_weights,
                    trial_comm, orig_vw, orig_N, total_weight, resolution);
                if (new_Q <= level_best) break;
                level_best = new_Q;
            }

            cudaFree(ml_comm);
            if (c_off2) cudaFree(c_off2);
            if (c_idx2_owned) cudaFree(c_idx2_owned);
            if (c_wt2) cudaFree(c_wt2);
            if (c_vw2) cudaFree(c_vw2);

            float trial_Q = compute_modularity(cache, offsets, indices, edge_weights,
                trial_comm, orig_vw, orig_N, total_weight, resolution);
            if (trial_Q > overall_best_Q) {
                overall_best_Q = trial_Q;
                cudaMemcpy(clusters, trial_comm, orig_N * sizeof(int32_t), cudaMemcpyDeviceToDevice);
            }
        }

        cudaFree(all_comm); cudaFree(all_sigma); cudaFree(all_mod);
        cudaFree(trial_comm); cudaFree(d_lc);
    }


    {
        int32_t* par_comm; cudaMalloc(&par_comm, orig_N * sizeof(int32_t));
        init_communities_kernel<<<(orig_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(par_comm, orig_N);

        int cur_N = orig_N, cur_E = orig_E;
        const int32_t* cur_off = offsets;
        const int32_t* cur_idx2 = indices;
        const float* cur_wt = edge_weights;
        const float* cur_vw = orig_vw;
        int32_t* c_off = nullptr; int32_t* c_idx = nullptr;
        float* c_wt = nullptr; float* c_vw = nullptr;
        float best_modularity = -1.0f;
        int par_levels = 0;

        for (int level = 0; level < (int)max_level; level++) {
            int32_t* comm; cudaMalloc(&comm, cur_N * sizeof(int32_t));
            float* sigma; cudaMalloc(&sigma, cur_N * sizeof(float));
            int32_t* bm_comm; cudaMalloc(&bm_comm, cur_N * sizeof(int32_t));
            float* bm_gain; cudaMalloc(&bm_gain, cur_N * sizeof(float));
            int32_t* best_saved; cudaMalloc(&best_saved, cur_N * sizeof(int32_t));

            init_communities_kernel<<<(cur_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(comm, cur_N);
            float new_Q = compute_modularity(cache, cur_off, cur_idx2, cur_wt, comm,
                cur_vw, cur_N, total_weight, resolution);
            float cur_Q = new_Q - 1;
            cudaMemcpy(best_saved, comm, cur_N * sizeof(int32_t), cudaMemcpyDeviceToDevice);

            bool up_down = true;
            while (new_Q > cur_Q + threshold) {
                cur_Q = new_Q;
                cudaMemset(sigma, 0, cur_N * sizeof(float));
                recompute_sigma_tot_kernel<<<(cur_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(
                    comm, cur_vw, sigma, cur_N);

                { size_t smem_size = LM_BLOCK * HASH_CAP * (sizeof(int) + sizeof(float));
                  int grid = (cur_N + LM_BLOCK - 1) / LM_BLOCK;
                  compute_best_move_kernel<<<grid, LM_BLOCK, smem_size>>>(
                    cur_off, cur_idx2, cur_wt, comm, sigma, cur_vw,
                    cur_N, total_weight, resolution, bm_comm, bm_gain); }

                cudaMemset(d_count, 0, sizeof(int));
                count_updown_kernel<<<(cur_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(
                    comm, bm_comm, bm_gain, cur_N, up_down, d_count);
                int h_count;
                cudaMemcpy(&h_count, d_count, sizeof(int), cudaMemcpyDeviceToHost);
                bool eff = up_down; if (h_count == 0) eff = !up_down;
                apply_updown_kernel<<<(cur_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(
                    comm, bm_comm, bm_gain, cur_N, eff);
                up_down = !up_down;

                new_Q = compute_modularity(cache, cur_off, cur_idx2, cur_wt, comm,
                    cur_vw, cur_N, total_weight, resolution);
                if (new_Q > cur_Q)
                    cudaMemcpy(best_saved, comm, cur_N * sizeof(int32_t), cudaMemcpyDeviceToDevice);
            }

            cudaMemcpy(comm, best_saved, cur_N * sizeof(int32_t), cudaMemcpyDeviceToDevice);
            if (cur_Q <= best_modularity) {
                cudaFree(comm); cudaFree(sigma); cudaFree(bm_comm); cudaFree(bm_gain); cudaFree(best_saved);
                break;
            }
            best_modularity = cur_Q;

            int* used; cudaMalloc(&used, cur_N * sizeof(int));
            int* pref; cudaMalloc(&pref, cur_N * sizeof(int));
            int new_N = renumber_communities(cache, comm, used, pref, cur_N);
            cudaFree(used); cudaFree(pref);

            if (new_N >= cur_N) {
                cudaFree(comm); cudaFree(sigma); cudaFree(bm_comm); cudaFree(bm_gain); cudaFree(best_saved);
                break;
            }

            if (level == 0)
                cudaMemcpy(par_comm, comm, orig_N * sizeof(int32_t), cudaMemcpyDeviceToDevice);
            else
                compose_communities_kernel<<<(orig_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(par_comm, comm, orig_N);
            par_levels = level + 1;

            if (level + 1 >= (int)max_level) {
                cudaFree(comm); cudaFree(sigma); cudaFree(bm_comm); cudaFree(bm_gain); cudaFree(best_saved);
                break;
            }


            int32_t* old_c_off = c_off;
            int32_t* old_c_idx = c_idx;
            float* old_c_wt = c_wt;
            float* old_c_vw = c_vw;

            int new_E = coarsen_graph(cache, cur_off, cur_idx2, cur_wt, cur_vw,
                comm, cur_N, cur_E, new_N,
                &c_off, &c_idx, &c_wt, &c_vw);


            if (old_c_off) cudaFree(old_c_off);
            if (old_c_idx) cudaFree(old_c_idx);
            if (old_c_wt) cudaFree(old_c_wt);
            if (old_c_vw) cudaFree(old_c_vw);

            cur_N = new_N; cur_E = new_E;
            cur_off = c_off;
            cur_idx2 = c_idx;
            cur_wt = c_wt;
            cur_vw = c_vw;

            cudaFree(comm); cudaFree(sigma); cudaFree(bm_comm); cudaFree(bm_gain); cudaFree(best_saved);
        }


        {
            float* ref_sigma; cudaMalloc(&ref_sigma, orig_N * sizeof(float));
            int* d_ref_changed; cudaMalloc(&d_ref_changed, sizeof(int));
            int refine_max = (orig_N > 1000000) ? 10 : 50;
            for (int iter = 0; iter < refine_max; iter++) {
                cudaMemset(d_ref_changed, 0, sizeof(int));
                for (int c = 0; c < 2; c++) {
                    cudaMemset(ref_sigma, 0, orig_N * sizeof(float));
                    recompute_sigma_tot_kernel<<<(orig_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(
                        par_comm, orig_vw, ref_sigma, orig_N);
                    int num_verts = (orig_N + 2 - 1 - c) / 2;
                    if (num_verts > 0) {
                        int grid = (num_verts + LM_BLOCK - 1) / LM_BLOCK;
                        size_t smem_size = LM_BLOCK * HASH_CAP * (sizeof(int) + sizeof(float));
                        local_move_kernel<<<grid, LM_BLOCK, smem_size>>>(
                            offsets, indices, edge_weights,
                            par_comm, ref_sigma, orig_vw,
                            orig_N, total_weight, resolution, d_ref_changed, c, 2);
                    }
                }
                int h_changed = 0;
                cudaMemcpy(&h_changed, d_ref_changed, sizeof(int), cudaMemcpyDeviceToHost);
                if (!h_changed) break;
            }
            cudaFree(ref_sigma); cudaFree(d_ref_changed);
        }

        float par_Q = compute_modularity(cache, offsets, indices, edge_weights,
            par_comm, orig_vw, orig_N, total_weight, resolution);
        if (par_Q > overall_best_Q) {
            overall_best_Q = par_Q;
            cudaMemcpy(clusters, par_comm, orig_N * sizeof(int32_t), cudaMemcpyDeviceToDevice);
            actual_level_count = (par_levels > 0) ? (int64_t)par_levels : 1;
        }

        cudaFree(par_comm);
        if (c_off) cudaFree(c_off);
        if (c_idx) cudaFree(c_idx);
        if (c_wt) cudaFree(c_wt);
        if (c_vw) cudaFree(c_vw);
    }

    int* ru; cudaMalloc(&ru, (size_t)orig_N * sizeof(int));
    int* rp; cudaMalloc(&rp, (size_t)orig_N * sizeof(int));
    renumber_communities(cache, clusters, ru, rp, orig_N);
    cudaFree(ru); cudaFree(rp);

    float modularity = compute_modularity(cache, offsets, indices, edge_weights,
        clusters, orig_vw, orig_N, total_weight, resolution);

    cudaFree(orig_vw);
    cudaFree(d_count);

    return louvain_result_float_t{(std::size_t)actual_level_count, modularity};
}

