louvain_result_double_t louvain_seg(const graph32_t& graph,
                                    const double* edge_weights,
                                    int32_t* clusters,
                                    std::size_t max_level,
                                    double threshold,
                                    double resolution) {
    static int tag;
    auto& cache = cache_pool().acquire<Cache>(&tag);

    const int32_t* offsets = graph.offsets;
    const int32_t* indices = graph.indices;
    int32_t orig_N = graph.number_of_vertices;
    int32_t orig_E = graph.number_of_edges;
    float threshold_f = (float)threshold;
    float resolution_f = (float)resolution;


    float* edge_weights_f;
    cudaMalloc(&edge_weights_f, (size_t)orig_E * sizeof(float));
    if (orig_E > 0) {
        convert_d2f_kernel<<<(orig_E + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(edge_weights, edge_weights_f, orig_E);
    }


    float* orig_vw;
    cudaMalloc(&orig_vw, (size_t)orig_N * sizeof(float));
    compute_vertex_weights_kernel<<<(orig_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(offsets, edge_weights_f, orig_vw, orig_N);


    float* d_tw;
    cudaMalloc(&d_tw, sizeof(float));
    cudaMemset(d_tw, 0, sizeof(float));
    int grid_tw = (orig_N + BLOCK_SIZE - 1) / BLOCK_SIZE;
    if (grid_tw > 1024) grid_tw = 1024;
    reduce_sum_kernel<<<grid_tw, BLOCK_SIZE>>>(orig_vw, d_tw, orig_N);
    float total_weight;
    cudaMemcpy(&total_weight, d_tw, sizeof(float), cudaMemcpyDeviceToHost);
    cudaFree(d_tw);


    init_communities_kernel<<<(orig_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(clusters, orig_N);

    if (total_weight == 0.0f || orig_N <= 1) {
        cudaFree(edge_weights_f);
        cudaFree(orig_vw);
        return louvain_result_double_t{0, 0.0};
    }

    int* d_count;
    cudaMalloc(&d_count, sizeof(int));
    float overall_best_Q = -1.0f;


    if (orig_N <= 256) {
        int num_restarts = 2048;
        int32_t* all_comm; cudaMalloc(&all_comm, (size_t)num_restarts * orig_N * sizeof(int32_t));
        float* all_sigma; cudaMalloc(&all_sigma, (size_t)num_restarts * orig_N * sizeof(float));
        float* all_mod; cudaMalloc(&all_mod, (size_t)num_restarts * sizeof(float));

        batch_sequential_louvain_kernel<<<num_restarts, 1>>>(
            offsets, indices, edge_weights_f, orig_vw,
            orig_N, total_weight, resolution_f,
            all_comm, all_sigma, all_mod, num_restarts);
        cudaDeviceSynchronize();

        std::vector<float> h_mod(num_restarts);
        cudaMemcpy(h_mod.data(), all_mod, num_restarts * sizeof(float), cudaMemcpyDeviceToHost);
        std::vector<int> sorted_idx(num_restarts);
        for (int i = 0; i < num_restarts; i++) sorted_idx[i] = i;
        std::sort(sorted_idx.begin(), sorted_idx.end(), [&](int a, int b) { return h_mod[a] > h_mod[b]; });

        int topK = std::min(50, num_restarts);
        int32_t* trial_comm; cudaMalloc(&trial_comm, (size_t)orig_N * sizeof(int32_t));
        int* d_lc; cudaMalloc(&d_lc, sizeof(int));

        for (int ki = 0; ki < topK; ki++) {
            int idx = sorted_idx[ki];
            cudaMemcpy(trial_comm, all_comm + (int64_t)idx * orig_N,
                       orig_N * sizeof(int32_t), cudaMemcpyDeviceToDevice);

            int32_t* ml_comm; cudaMalloc(&ml_comm, (size_t)orig_N * sizeof(int32_t));
            cudaMemcpy(ml_comm, trial_comm, orig_N * sizeof(int32_t), cudaMemcpyDeviceToDevice);

            int cur_N = orig_N, cur_E = orig_E;
            const int32_t* cur_off = offsets;
            const int32_t* cur_idx2 = indices;
            const float* cur_wt = edge_weights_f;
            const float* cur_vw = orig_vw;

            int32_t* c_off2 = nullptr; int32_t* c_idx2_owned = nullptr;
            float* c_wt2 = nullptr; float* c_vw2 = nullptr;

            float level_best = h_mod[idx];
            bool first_level = true;

            for (int level = 0; level < (int)max_level; level++) {
                int32_t* used; cudaMalloc(&used, (size_t)cur_N * sizeof(int32_t));
                int32_t* pref; cudaMalloc(&pref, (size_t)cur_N * sizeof(int32_t));
                int new_N = renumber_communities(ml_comm, (int*)used, (int*)pref, cur_N, cache);
                cudaFree(used); cudaFree(pref);

                if (new_N >= cur_N) break;

                if (first_level) {
                    cudaMemcpy(trial_comm, ml_comm, orig_N * sizeof(int32_t), cudaMemcpyDeviceToDevice);
                    first_level = false;
                } else {
                    compose_communities_kernel<<<(orig_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(trial_comm, ml_comm, orig_N);
                }


                int32_t* old_c_off = c_off2;
                int32_t* old_c_idx = c_idx2_owned;
                float* old_c_wt = c_wt2;
                float* old_c_vw = c_vw2;

                int new_E;
                coarsen_graph(cur_off, cur_idx2, cur_wt, cur_vw,
                              ml_comm, cur_N, cur_E,
                              &c_off2, &c_idx2_owned, &c_wt2, &c_vw2,
                              nullptr, new_N, &new_E, cache);


                if (old_c_off) { cudaFree(old_c_off); cudaFree(old_c_idx); cudaFree(old_c_wt); cudaFree(old_c_vw); }

                cur_N = new_N; cur_E = new_E;
                cur_off = c_off2;
                cur_idx2 = c_idx2_owned;
                cur_wt = c_wt2;
                cur_vw = c_vw2;

                cudaFree(ml_comm);
                cudaMalloc(&ml_comm, (size_t)cur_N * sizeof(int32_t));
                float* ls; cudaMalloc(&ls, (size_t)cur_N * sizeof(float));

                init_communities_kernel<<<(cur_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(ml_comm, cur_N);

                for (int iter = 0; iter < 200; iter++) {
                    cudaMemset(ls, 0, cur_N * sizeof(float));
                    recompute_sigma_tot_kernel<<<(cur_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(ml_comm, cur_vw, ls, cur_N);
                    cudaMemset(d_lc, 0, sizeof(int));
                    sequential_local_move_kernel<<<1, 1>>>(cur_off, cur_idx2, cur_wt,
                        ml_comm, ls, cur_vw, cur_N, total_weight, resolution_f, d_lc, 0);
                    int h_changed = 0;
                    cudaMemcpy(&h_changed, d_lc, sizeof(int), cudaMemcpyDeviceToHost);
                    if (!h_changed) break;
                }

                compose_communities_kernel<<<(orig_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(trial_comm, ml_comm, orig_N);

                float new_Q = compute_modularity(offsets, indices, edge_weights_f,
                    trial_comm, orig_vw, orig_N, total_weight, resolution_f);

                cudaFree(ls);

                if (new_Q <= level_best) break;
                level_best = new_Q;
            }

            if (c_off2) { cudaFree(c_off2); cudaFree(c_idx2_owned); cudaFree(c_wt2); cudaFree(c_vw2); }
            c_off2 = nullptr; c_idx2_owned = nullptr; c_wt2 = nullptr; c_vw2 = nullptr;

            float trial_Q = compute_modularity(offsets, indices, edge_weights_f,
                trial_comm, orig_vw, orig_N, total_weight, resolution_f);
            if (trial_Q > overall_best_Q) {
                overall_best_Q = trial_Q;
                cudaMemcpy(clusters, trial_comm, orig_N * sizeof(int32_t), cudaMemcpyDeviceToDevice);
            }

            cudaFree(ml_comm);
        }

        cudaFree(trial_comm); cudaFree(d_lc);
        cudaFree(all_comm); cudaFree(all_sigma); cudaFree(all_mod);
    }


    {
        int32_t* par_comm; cudaMalloc(&par_comm, (size_t)orig_N * sizeof(int32_t));
        init_communities_kernel<<<(orig_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(par_comm, orig_N);

        int cur_N = orig_N, cur_E = orig_E;
        const int32_t* cur_off = offsets;
        const int32_t* cur_idx2 = indices;
        const float* cur_wt = edge_weights_f;
        const float* cur_vw = orig_vw;

        int32_t* c_off = nullptr; int32_t* c_idx = nullptr;
        float* c_wt = nullptr; float* c_vw = nullptr;

        float best_modularity = -1.0f;

        for (int level = 0; level < (int)max_level; level++) {
            int32_t* comm; cudaMalloc(&comm, (size_t)cur_N * sizeof(int32_t));
            float* sigma; cudaMalloc(&sigma, (size_t)cur_N * sizeof(float));
            int32_t* bm_comm; cudaMalloc(&bm_comm, (size_t)cur_N * sizeof(int32_t));
            float* bm_gain; cudaMalloc(&bm_gain, (size_t)cur_N * sizeof(float));
            int32_t* best_saved; cudaMalloc(&best_saved, (size_t)cur_N * sizeof(int32_t));

            init_communities_kernel<<<(cur_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(comm, cur_N);

            float new_Q = compute_modularity(cur_off, cur_idx2, cur_wt, comm,
                cur_vw, cur_N, total_weight, resolution_f);
            float cur_Q = new_Q - 1;
            cudaMemcpy(best_saved, comm, cur_N * sizeof(int32_t), cudaMemcpyDeviceToDevice);

            bool up_down = true;
            while (new_Q > cur_Q + threshold_f) {
                cur_Q = new_Q;
                cudaMemset(sigma, 0, cur_N * sizeof(float));
                recompute_sigma_tot_kernel<<<(cur_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(comm, cur_vw, sigma, cur_N);

                if (cur_N > 0) {
                    int grid_bm = (cur_N + LM_BLOCK - 1) / LM_BLOCK;
                    size_t smem_bm = LM_BLOCK * HASH_CAP * (sizeof(int) + sizeof(float));
                    compute_best_move_kernel<<<grid_bm, LM_BLOCK, smem_bm>>>(
                        cur_off, cur_idx2, cur_wt, comm, sigma, cur_vw,
                        cur_N, total_weight, resolution_f, bm_comm, bm_gain);
                }

                cudaMemset(d_count, 0, sizeof(int));
                if (cur_N > 0) {
                    count_updown_kernel<<<(cur_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(
                        comm, bm_comm, bm_gain, cur_N, up_down, d_count);
                }
                int h_count;
                cudaMemcpy(&h_count, d_count, sizeof(int), cudaMemcpyDeviceToHost);
                bool eff = up_down; if (h_count == 0) eff = !up_down;

                if (cur_N > 0) {
                    apply_updown_kernel<<<(cur_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(
                        comm, bm_comm, bm_gain, cur_N, eff);
                }

                up_down = !up_down;
                new_Q = compute_modularity(cur_off, cur_idx2, cur_wt, comm,
                    cur_vw, cur_N, total_weight, resolution_f);
                if (new_Q > cur_Q) {
                    cudaMemcpy(best_saved, comm, cur_N * sizeof(int32_t), cudaMemcpyDeviceToDevice);
                }
            }

            cudaMemcpy(comm, best_saved, cur_N * sizeof(int32_t), cudaMemcpyDeviceToDevice);

            bool level_done = false;

            if (cur_Q <= best_modularity) {
                level_done = true;
            }

            int new_N = 0;
            if (!level_done) {
                best_modularity = cur_Q;
                int32_t* used; cudaMalloc(&used, (size_t)cur_N * sizeof(int32_t));
                int32_t* pref; cudaMalloc(&pref, (size_t)cur_N * sizeof(int32_t));
                new_N = renumber_communities(comm, (int*)used, (int*)pref, cur_N, cache);
                cudaFree(used); cudaFree(pref);

                if (new_N >= cur_N) {
                    level_done = true;
                }
            }

            if (!level_done) {
                if (level == 0) {
                    cudaMemcpy(par_comm, comm, orig_N * sizeof(int32_t), cudaMemcpyDeviceToDevice);
                } else {
                    compose_communities_kernel<<<(orig_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(par_comm, comm, orig_N);
                }

                if (level + 1 >= (int)max_level) {
                    level_done = true;
                }
            }

            if (!level_done) {

                int32_t* old_c_off = c_off;
                int32_t* old_c_idx = c_idx;
                float* old_c_wt = c_wt;
                float* old_c_vw = c_vw;

                int new_E;
                coarsen_graph(cur_off, cur_idx2, cur_wt, cur_vw,
                              comm, cur_N, cur_E,
                              &c_off, &c_idx, &c_wt, &c_vw,
                              nullptr, new_N, &new_E, cache);

                if (old_c_off) { cudaFree(old_c_off); cudaFree(old_c_idx); cudaFree(old_c_wt); cudaFree(old_c_vw); }

                cur_N = new_N; cur_E = new_E;
                cur_off = c_off; cur_idx2 = c_idx;
                cur_wt = c_wt; cur_vw = c_vw;
            }

            cudaFree(comm); cudaFree(sigma); cudaFree(bm_comm); cudaFree(bm_gain); cudaFree(best_saved);

            if (level_done) break;
        }


        {
            float* ref_sigma; cudaMalloc(&ref_sigma, (size_t)orig_N * sizeof(float));
            int* d_ref_changed; cudaMalloc(&d_ref_changed, sizeof(int));
            int refine_max = (orig_N > 1000000) ? 10 : 50;
            for (int iter = 0; iter < refine_max; iter++) {
                cudaMemset(d_ref_changed, 0, sizeof(int));
                for (int c = 0; c < 2; c++) {
                    cudaMemset(ref_sigma, 0, orig_N * sizeof(float));
                    recompute_sigma_tot_kernel<<<(orig_N + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(par_comm, orig_vw, ref_sigma, orig_N);

                    int num_verts = (orig_N + 2 - 1 - c) / 2;
                    if (num_verts > 0) {
                        int grid_lm = (num_verts + LM_BLOCK - 1) / LM_BLOCK;
                        size_t smem_lm = LM_BLOCK * HASH_CAP * (sizeof(int) + sizeof(float));
                        local_move_kernel<<<grid_lm, LM_BLOCK, smem_lm>>>(
                            offsets, indices, edge_weights_f,
                            par_comm, ref_sigma, orig_vw,
                            orig_N, total_weight, resolution_f, d_ref_changed, c, 2);
                    }
                }
                int h_changed = 0;
                cudaMemcpy(&h_changed, d_ref_changed, sizeof(int), cudaMemcpyDeviceToHost);
                if (!h_changed) break;
            }
            cudaFree(ref_sigma); cudaFree(d_ref_changed);
        }

        float par_Q = compute_modularity(offsets, indices, edge_weights_f,
            par_comm, orig_vw, orig_N, total_weight, resolution_f);
        if (par_Q > overall_best_Q) {
            overall_best_Q = par_Q;
            cudaMemcpy(clusters, par_comm, orig_N * sizeof(int32_t), cudaMemcpyDeviceToDevice);
        }

        if (c_off) { cudaFree(c_off); cudaFree(c_idx); cudaFree(c_wt); cudaFree(c_vw); }
        cudaFree(par_comm);
    }

    int* ru; cudaMalloc(&ru, (size_t)orig_N * sizeof(int));
    int* rp; cudaMalloc(&rp, (size_t)orig_N * sizeof(int));
    renumber_communities(clusters, ru, rp, orig_N, cache);
    cudaFree(ru); cudaFree(rp);


    float modularity = compute_modularity(offsets, indices, edge_weights_f,
        clusters, orig_vw, orig_N, total_weight, resolution_f);

    cudaFree(edge_weights_f);
    cudaFree(orig_vw);
    cudaFree(d_count);

    return louvain_result_double_t{1, (double)modularity};
}

