struct Cache : Cacheable {
    int32_t* masked_deg = nullptr;
    int32_t* dodg_deg = nullptr;
    int32_t* dodg_offsets = nullptr;
    void* scan_temp = nullptr;
    int32_t* dodg_indices = nullptr;
    int32_t* all_counts = nullptr;

    int64_t masked_deg_capacity = 0;
    int64_t dodg_deg_capacity = 0;
    int64_t dodg_offsets_capacity = 0;
    size_t scan_temp_capacity = 0;
    int64_t dodg_indices_capacity = 0;
    int64_t all_counts_capacity = 0;

    void ensure(int32_t num_vertices, int32_t num_edges, bool need_all_counts) {
        if (masked_deg_capacity < num_vertices) {
            if (masked_deg) cudaFree(masked_deg);
            cudaMalloc(&masked_deg, (size_t)num_vertices * sizeof(int32_t));
            masked_deg_capacity = num_vertices;
        }
        if (dodg_deg_capacity < num_vertices) {
            if (dodg_deg) cudaFree(dodg_deg);
            cudaMalloc(&dodg_deg, (size_t)num_vertices * sizeof(int32_t));
            dodg_deg_capacity = num_vertices;
        }
        int64_t off_size = (int64_t)num_vertices + 1;
        if (dodg_offsets_capacity < off_size) {
            if (dodg_offsets) cudaFree(dodg_offsets);
            cudaMalloc(&dodg_offsets, (size_t)off_size * sizeof(int32_t));
            dodg_offsets_capacity = off_size;
        }
        size_t needed_scan_temp = 0;
        cub::DeviceScan::InclusiveSum(nullptr, needed_scan_temp, (int32_t*)nullptr, (int32_t*)nullptr, num_vertices);
        if (scan_temp_capacity < needed_scan_temp) {
            if (scan_temp) cudaFree(scan_temp);
            cudaMalloc(&scan_temp, needed_scan_temp);
            scan_temp_capacity = needed_scan_temp;
        }
        int64_t dodg_alloc = (int64_t)(num_edges / 2) + 1;
        if (dodg_indices_capacity < dodg_alloc) {
            if (dodg_indices) cudaFree(dodg_indices);
            cudaMalloc(&dodg_indices, (size_t)dodg_alloc * sizeof(int32_t));
            dodg_indices_capacity = dodg_alloc;
        }
        if (need_all_counts) {
            if (all_counts_capacity < num_vertices) {
                if (all_counts) cudaFree(all_counts);
                cudaMalloc(&all_counts, (size_t)num_vertices * sizeof(int32_t));
                all_counts_capacity = num_vertices;
            }
        }
    }

    ~Cache() override {
        if (masked_deg) cudaFree(masked_deg);
        if (dodg_deg) cudaFree(dodg_deg);
        if (dodg_offsets) cudaFree(dodg_offsets);
        if (scan_temp) cudaFree(scan_temp);
        if (dodg_indices) cudaFree(dodg_indices);
        if (all_counts) cudaFree(all_counts);
