    if (u >= v_end) return;

    int start = offsets[u];
    int end = offsets[u + 1];

    for (int e = start + threadIdx.x; e < end; e += blockDim.x) {
        if ((edge_mask[e >> 5] >> (e & 31)) & 1u) {
