        cudaMalloc(&buf1, n * sizeof(int32_t));
        cudaMalloc(&buf2, n * sizeof(int32_t));
        cudaMalloc(&frontier, n * sizeof(int32_t));
        cudaMalloc(&dest_list, n * sizeof(int32_t));
        cudaMalloc(&counters, 8 * sizeof(int32_t));
