                          int32_t E, cudaStream_t stream)
{
    if (E == 0) return;
    int threads = 256;
    int blocks = (E + threads - 1) / threads;
    if (blocks > 65535) blocks = 65535;
    count_degrees_kernel<<<blocks, threads, 0, stream>>>(indices, counts, E);
}

