    void ensure_temp_hubs(int64_t n) {
        if (temp_hubs_capacity < n) {
            if (d_temp_hubs) cudaFree(d_temp_hubs);
            cudaMalloc(&d_temp_hubs, n * sizeof(double));
            temp_hubs_capacity = n;
