}

void launch_fill(float* data, int32_t n, float val, cudaStream_t s) {
    if (n <= 0) return;
    int blk = 256, grid = (n + blk - 1) / blk;
    fill_kernel<<<grid, blk, 0, s>>>(data, n, val);
