            cudaMalloc(&pr_a, (size_t)n * sizeof(float));
            cudaMalloc(&pr_b, (size_t)n * sizeof(float));
            cudaMalloc(&x, (size_t)n * sizeof(float));
            cudaMalloc(&scalar_buf, 2 * sizeof(float));

