struct Cache : Cacheable {

    cusparseHandle_t cusparse_handle = nullptr;
    float* d_spmv_alpha = nullptr;
    float* d_spmv_beta = nullptr;


    int32_t* out_degree = nullptr;
    float* inv_out_weight = nullptr;
