__global__ void iota_kernel(int32_t* out, int32_t n) {
  int tid = blockIdx.x * blockDim.x + threadIdx.x;
  if (tid < n) out[tid] = tid;
}

void launch_iota(int32_t* out, int32_t n) {
  if (n <= 0) return;
  iota_kernel<<<(n + 255) / 256, 256>>>(out, n);
