template <typename KeyT>
struct NotSelfPair {
  int v_bits;
  KeyT v_mask;
  const int32_t* seeds;

  __device__ __forceinline__ bool operator()(KeyT key) const {
    int32_t sid = (int32_t)((uint64_t)key >> v_bits);
    int32_t v = (int32_t)((uint64_t)key & (uint64_t)v_mask);
    int32_t u = __ldg(&seeds[sid]);
    return u != v;
  }
};

