  constexpr int warps_per_block = 8;
  int threads = warps_per_block * 32;
  int blocks = (int)((num_pairs + warps_per_block - 1) / warps_per_block);
  int smem_bytes = SMEM_MAX_DEGREE * (int)(sizeof(double) + sizeof(int32_t));
