similarity_result_double_t cosine_all_pairs_similarity_seg(const graph32_t& graph,
                                                           const double* edge_weights,
                                                           const int32_t* vertices,
                                                           std::size_t num_vertices,
                                                           std::optional<std::size_t> topk) {
    static int tag;
    auto& cache = cache_pool().acquire<Cache>(&tag);

    const int32_t* d_offsets = graph.offsets;
    const int32_t* d_indices = graph.indices;
    int32_t n_verts = graph.number_of_vertices;
    int32_t n_edges = graph.number_of_edges;
    const double* d_weights = edge_weights;

    bool has_topk = topk.has_value();
    int64_t topk_val = has_topk ? (int64_t)topk.value() : 0;


    int32_t num_seeds;
    const int32_t* d_seeds;
    int32_t* d_seeds_alloc = nullptr;
    if (vertices != nullptr && num_vertices > 0) {
        d_seeds = vertices;
        num_seeds = (int32_t)num_vertices;
    } else {
        cudaMalloc(&d_seeds_alloc, (int64_t)n_verts * sizeof(int32_t));
        fill_sequence_kernel<<<(n_verts + 511) / 512, 512>>>(d_seeds_alloc, n_verts);
        d_seeds = d_seeds_alloc;
        num_seeds = n_verts;
    }

    if (num_seeds == 0 || n_edges == 0) {
        if (d_seeds_alloc) cudaFree(d_seeds_alloc);
        return {nullptr, nullptr, nullptr, 0};
    }


    if (has_topk && topk_val > 0) {
        int32_t* eager_first;  cudaMalloc(&eager_first, topk_val * sizeof(int32_t));
        int32_t* eager_second; cudaMalloc(&eager_second, topk_val * sizeof(int32_t));
        double*  eager_scores; cudaMalloc(&eager_scores, topk_val * sizeof(double));

        cudaMemsetAsync(cache.d_counter, 0, sizeof(int32_t));

        eager_cosine_topk_kernel<<<num_seeds, 512>>>(
            d_offsets, d_indices, d_seeds, num_seeds,
            eager_first, eager_second, eager_scores,
            cache.d_counter, (int)topk_val);

        int32_t found;
        cudaMemcpy(&found, cache.d_counter, sizeof(int32_t), cudaMemcpyDeviceToHost);

        if (found >= (int32_t)topk_val) {
            if (d_seeds_alloc) cudaFree(d_seeds_alloc);
            return {eager_first, eager_second, eager_scores, (std::size_t)topk_val};
        }

        cudaFree(eager_first);
        cudaFree(eager_second);
        cudaFree(eager_scores);
    }


    int64_t* d_ht_sizes;    cudaMalloc(&d_ht_sizes, (int64_t)num_seeds * sizeof(int64_t));
    int64_t* d_raw_totals;  cudaMalloc(&d_raw_totals, (int64_t)num_seeds * sizeof(int64_t));
    compute_ht_sizes_kernel<<<num_seeds, 512>>>(d_offsets, d_indices, d_seeds, num_seeds, n_verts,
                                                 d_ht_sizes, d_raw_totals);


    int64_t* d_ht_offsets; cudaMalloc(&d_ht_offsets, ((int64_t)num_seeds + 1) * sizeof(int64_t));
    {
        thrust::device_ptr<int64_t> in_ptr(d_ht_sizes);
        thrust::device_ptr<int64_t> out_ptr(d_ht_offsets);
        thrust::inclusive_scan(in_ptr, in_ptr + num_seeds, out_ptr + 1);
        cudaMemsetAsync(d_ht_offsets, 0, sizeof(int64_t));
    }

    int64_t total_ht_size;
    cudaMemcpy(&total_ht_size, d_ht_offsets + num_seeds,
               sizeof(int64_t), cudaMemcpyDeviceToHost);

    int32_t* d_ht_keys = nullptr;
    int32_t* d_ht_counts = nullptr;
    if (total_ht_size > 0) {
        cudaMalloc(&d_ht_keys, total_ht_size * sizeof(int32_t));
        cudaMalloc(&d_ht_counts, total_ht_size * sizeof(int32_t));
        init_ht_kernel<<<(int)((total_ht_size + 511) / 512), 512>>>(d_ht_keys, total_ht_size);
        cudaMemsetAsync(d_ht_counts, 0, total_ht_size * sizeof(int32_t));

        count_2hop_kernel<<<num_seeds, 512>>>(d_offsets, d_indices, d_seeds, num_seeds,
                                              d_ht_keys, d_ht_counts, d_ht_offsets, d_ht_sizes);
    }

    int64_t* d_pair_counts;   cudaMalloc(&d_pair_counts, (int64_t)num_seeds * sizeof(int64_t));
    int64_t* d_count1_counts; cudaMalloc(&d_count1_counts, (int64_t)num_seeds * sizeof(int64_t));
    if (total_ht_size > 0) {
        count_pairs_kernel<<<num_seeds, 512>>>(d_ht_keys, d_ht_counts, d_ht_offsets, d_ht_sizes,
                                                num_seeds, d_pair_counts, d_count1_counts);
    } else {
        cudaMemsetAsync(d_pair_counts, 0, num_seeds * sizeof(int64_t));
        cudaMemsetAsync(d_count1_counts, 0, num_seeds * sizeof(int64_t));
    }

    cudaDeviceSynchronize();
    int64_t hash_total_pairs;
    {
        thrust::device_ptr<int64_t> ptr(d_pair_counts);
        hash_total_pairs = thrust::reduce(ptr, ptr + num_seeds, (int64_t)0);
    }


    int32_t* d_hash_first = nullptr;
    int32_t* d_hash_second = nullptr;
    double*  d_hash_scores = nullptr;
    if (hash_total_pairs > 0) {
        int64_t* d_pair_offsets; cudaMalloc(&d_pair_offsets, ((int64_t)num_seeds + 1) * sizeof(int64_t));
        {
            thrust::device_ptr<int64_t> in_ptr(d_pair_counts);
            thrust::device_ptr<int64_t> out_ptr(d_pair_offsets);
            thrust::inclusive_scan(in_ptr, in_ptr + num_seeds, out_ptr + 1);
            cudaMemsetAsync(d_pair_offsets, 0, sizeof(int64_t));
        }

        cudaMalloc(&d_hash_first, hash_total_pairs * sizeof(int32_t));
        cudaMalloc(&d_hash_second, hash_total_pairs * sizeof(int32_t));
        cudaMalloc(&d_hash_scores, hash_total_pairs * sizeof(double));
        int32_t* d_counters; cudaMalloc(&d_counters, (int64_t)num_seeds * sizeof(int32_t));
        cudaMemsetAsync(d_counters, 0, num_seeds * sizeof(int32_t));

        extract_and_score_kernel<<<num_seeds, 512>>>(
            d_offsets, d_indices, d_weights, d_seeds, num_seeds,
            d_ht_keys, d_ht_counts, d_ht_offsets, d_ht_sizes,
            d_pair_offsets,
            d_hash_first, d_hash_second, d_hash_scores, d_counters);

        cudaFree(d_pair_offsets);
        cudaFree(d_counters);
    }


    std::vector<int64_t> h_ht_sizes(num_seeds), h_raw_totals(num_seeds);
    cudaMemcpy(h_ht_sizes.data(), d_ht_sizes,
               num_seeds * sizeof(int64_t), cudaMemcpyDeviceToHost);
    cudaMemcpy(h_raw_totals.data(), d_raw_totals,
               num_seeds * sizeof(int64_t), cudaMemcpyDeviceToHost);


    cudaFree(d_ht_sizes);
    cudaFree(d_raw_totals);
    cudaFree(d_ht_offsets);
    if (d_ht_keys) cudaFree(d_ht_keys);
    if (d_ht_counts) cudaFree(d_ht_counts);
    cudaFree(d_pair_counts);
    cudaFree(d_count1_counts);

    bool has_fallback = false;
    for (int i = 0; i < num_seeds; i++) {
        if (h_ht_sizes[i] == 0 && h_raw_totals[i] > 0) { has_fallback = true; break; }
    }

    if (!has_fallback) {
        if (d_seeds_alloc) cudaFree(d_seeds_alloc);


        if (hash_total_pairs == 0) {
            return {nullptr, nullptr, nullptr, 0};
        }

        if (has_topk && hash_total_pairs > topk_val) {
            int32_t* final_first;  cudaMalloc(&final_first, topk_val * sizeof(int32_t));
            int32_t* final_second; cudaMalloc(&final_second, topk_val * sizeof(int32_t));
            double*  final_scores; cudaMalloc(&final_scores, topk_val * sizeof(double));
            int32_t* d_perm;       cudaMalloc(&d_perm, hash_total_pairs * sizeof(int32_t));

            thrust::device_ptr<int32_t> pp(d_perm);
            thrust::sequence(pp, pp + hash_total_pairs);
            ScoreDescComp cmp; cmp.scores = d_hash_scores;
            thrust::sort(pp, pp + hash_total_pairs, cmp);
            gather_kernel<<<(int)((topk_val + 511) / 512), 512>>>(
                d_hash_first, d_hash_second, d_hash_scores, d_perm,
                final_first, final_second, final_scores, topk_val);

            cudaFree(d_perm);
            cudaFree(d_hash_first);
            cudaFree(d_hash_second);
            cudaFree(d_hash_scores);
            return {final_first, final_second, final_scores, (std::size_t)topk_val};
        }

        return {d_hash_first, d_hash_second, d_hash_scores, (std::size_t)hash_total_pairs};
    }


    std::vector<int32_t*> fb_firsts, fb_seconds;
    std::vector<double*> fb_scores_vec;
    std::vector<int32_t> fb_counts;
    int64_t fb_total = 0;

    for (int i = 0; i < num_seeds; i++) {
        if (h_ht_sizes[i] != 0 || h_raw_totals[i] <= 0) continue;
        int64_t raw_total = h_raw_totals[i];


        int32_t h_seed;
        cudaMemcpy(&h_seed, d_seeds + i, sizeof(int32_t), cudaMemcpyDeviceToHost);
        int32_t h_off[2];
        cudaMemcpy(h_off, d_offsets + h_seed, 2 * sizeof(int32_t), cudaMemcpyDeviceToHost);
        int32_t u_start = h_off[0], u_end = h_off[1];
        int u_deg = u_end - u_start;
        if (u_deg == 0) continue;


        int64_t* d_nbr_degs; cudaMalloc(&d_nbr_degs, (int64_t)u_deg * sizeof(int64_t));
        compute_nbr_degrees_kernel<<<(u_deg + 511) / 512, 512>>>(d_offsets, d_indices, u_start, u_end,
                                                                   d_nbr_degs);

        int64_t* d_write_offs; cudaMalloc(&d_write_offs, ((int64_t)u_deg + 1) * sizeof(int64_t));
        {
            thrust::device_ptr<int64_t> in_ptr(d_nbr_degs);
            thrust::device_ptr<int64_t> out_ptr(d_write_offs);
            thrust::inclusive_scan(in_ptr, in_ptr + u_deg, out_ptr + 1);
            cudaMemsetAsync(d_write_offs, 0, sizeof(int64_t));
        }
        cudaFree(d_nbr_degs);


        int32_t* d_gather_buf; cudaMalloc(&d_gather_buf, raw_total * sizeof(int32_t));
        gather_2hop_kernel<<<u_deg, 512>>>(d_offsets, d_indices, u_start, u_end,
                                           d_gather_buf, d_write_offs);
        cudaFree(d_write_offs);


        {
            thrust::device_ptr<int32_t> ptr(d_gather_buf);
            thrust::sort(ptr, ptr + raw_total);
        }


        int32_t* d_unique_v; cudaMalloc(&d_unique_v, raw_total * sizeof(int32_t));
        int32_t* d_unique_c; cudaMalloc(&d_unique_c, raw_total * sizeof(int32_t));
        cudaDeviceSynchronize();
        int64_t n_unique;
        {
            thrust::device_ptr<const int32_t> in_ptr(d_gather_buf);
            thrust::device_ptr<int32_t> keys_ptr(d_unique_v);
            thrust::device_ptr<int32_t> counts_ptr(d_unique_c);
            auto end = thrust::reduce_by_key(
                in_ptr, in_ptr + raw_total,
                thrust::constant_iterator<int32_t>(1),
                keys_ptr, counts_ptr);
            n_unique = end.first - keys_ptr;
        }
        cudaFree(d_gather_buf);

        if (n_unique == 0) {
            cudaFree(d_unique_v);
            cudaFree(d_unique_c);
            continue;
        }


        int32_t* d_fb_first;  cudaMalloc(&d_fb_first, n_unique * sizeof(int32_t));
        int32_t* d_fb_second; cudaMalloc(&d_fb_second, n_unique * sizeof(int32_t));
        double*  d_fb_score;  cudaMalloc(&d_fb_score, n_unique * sizeof(double));
        int32_t* d_fb_counter; cudaMalloc(&d_fb_counter, sizeof(int32_t));
        cudaMemsetAsync(d_fb_counter, 0, sizeof(int32_t));

        int blocks = (int)((n_unique + 511) / 512);
        score_unique_pairs_kernel<<<blocks, 512>>>(
            d_offsets, d_indices, d_weights,
            h_seed, u_start, u_end,
            d_unique_v, d_unique_c, n_unique,
            d_fb_first, d_fb_second, d_fb_score, d_fb_counter);

        cudaFree(d_unique_v);
        cudaFree(d_unique_c);

        int32_t fb_count;
        cudaMemcpy(&fb_count, d_fb_counter, sizeof(int32_t), cudaMemcpyDeviceToHost);
        cudaFree(d_fb_counter);

        if (fb_count > 0) {
            fb_firsts.push_back(d_fb_first);
            fb_seconds.push_back(d_fb_second);
            fb_scores_vec.push_back(d_fb_score);
            fb_counts.push_back(fb_count);
            fb_total += fb_count;
        } else {
            cudaFree(d_fb_first);
            cudaFree(d_fb_second);
            cudaFree(d_fb_score);
        }
    }


    int64_t grand_total = hash_total_pairs + fb_total;
    if (grand_total == 0) {
        if (d_seeds_alloc) cudaFree(d_seeds_alloc);
        if (d_hash_first) cudaFree(d_hash_first);
        if (d_hash_second) cudaFree(d_hash_second);
        if (d_hash_scores) cudaFree(d_hash_scores);
        return {nullptr, nullptr, nullptr, 0};
    }

    int32_t* d_out_first;  cudaMalloc(&d_out_first, grand_total * sizeof(int32_t));
    int32_t* d_out_second; cudaMalloc(&d_out_second, grand_total * sizeof(int32_t));
    double*  d_out_scores; cudaMalloc(&d_out_scores, grand_total * sizeof(double));

    int64_t offset = 0;
    if (hash_total_pairs > 0) {
        cudaMemcpyAsync(d_out_first, d_hash_first,
                        hash_total_pairs * sizeof(int32_t), cudaMemcpyDeviceToDevice);
        cudaMemcpyAsync(d_out_second, d_hash_second,
                        hash_total_pairs * sizeof(int32_t), cudaMemcpyDeviceToDevice);
        cudaMemcpyAsync(d_out_scores, d_hash_scores,
                        hash_total_pairs * sizeof(double), cudaMemcpyDeviceToDevice);
        offset = hash_total_pairs;
    }
    if (d_hash_first) cudaFree(d_hash_first);
    if (d_hash_second) cudaFree(d_hash_second);
    if (d_hash_scores) cudaFree(d_hash_scores);

    for (size_t fi = 0; fi < fb_firsts.size(); fi++) {
        int32_t cnt = fb_counts[fi];
        cudaMemcpyAsync(d_out_first + offset, fb_firsts[fi],
                        cnt * sizeof(int32_t), cudaMemcpyDeviceToDevice);
        cudaMemcpyAsync(d_out_second + offset, fb_seconds[fi],
                        cnt * sizeof(int32_t), cudaMemcpyDeviceToDevice);
        cudaMemcpyAsync(d_out_scores + offset, fb_scores_vec[fi],
                        cnt * sizeof(double), cudaMemcpyDeviceToDevice);
        offset += cnt;
    }
    for (size_t fi = 0; fi < fb_firsts.size(); fi++) {
        cudaFree(fb_firsts[fi]);
        cudaFree(fb_seconds[fi]);
        cudaFree(fb_scores_vec[fi]);
    }

    if (d_seeds_alloc) cudaFree(d_seeds_alloc);

    if (has_topk && grand_total > topk_val) {
        int32_t* final_first;  cudaMalloc(&final_first, topk_val * sizeof(int32_t));
        int32_t* final_second; cudaMalloc(&final_second, topk_val * sizeof(int32_t));
        double*  final_scores; cudaMalloc(&final_scores, topk_val * sizeof(double));
        int32_t* d_perm;       cudaMalloc(&d_perm, grand_total * sizeof(int32_t));

        thrust::device_ptr<int32_t> pp(d_perm);
        thrust::sequence(pp, pp + grand_total);
        ScoreDescComp cmp; cmp.scores = d_out_scores;
        thrust::sort(pp, pp + grand_total, cmp);
        gather_kernel<<<(int)((topk_val + 511) / 512), 512>>>(
            d_out_first, d_out_second, d_out_scores, d_perm,
            final_first, final_second, final_scores, topk_val);

        cudaFree(d_perm);
        cudaFree(d_out_first);
        cudaFree(d_out_second);
        cudaFree(d_out_scores);
        return {final_first, final_second, final_scores, (std::size_t)topk_val};
    }

    return {d_out_first, d_out_second, d_out_scores, (std::size_t)grand_total};
}

