    uint32_t* bitmap = global_bitmaps + (int64_t)si * bitmap_words;
    int u = get_seed(seeds, si);
    build_bitmap<BLOCK_SIZE>(offsets, indices, u, bitmap_words, bitmap);
    int total = count_bitmap<BLOCK_SIZE>(bitmap, bitmap_words);

    if (total == 0) return;

