        } else {
            if (nseeds > 0) expand_2hop_thread32_kernel<<<((int)nseeds + 255) / 256, 256, 0, stream>>>(d_off, d_ind, d_seeds, (int32_t)nseeds, nv_bits, d_pfx, d_k32);
