        uint32_t nv_mask32 = (1u << nv_bits) - 1;
        if (!is_multi) {
            int64_t g = (num_runs + 255) / 256; int grid = (int)std::min(g, (int64_t)INT_MAX);
            compute_from_rle32_kernel<<<grid, 256, 0, stream>>>(d_off, d_seeds, d_uk32, d_counts, num_runs, nv_bits, nv_mask32,
