        cudaFree(d_of); cudaFree(d_os); cudaFree(d_osc);
        return {d_rf, d_rs, d_rsc, (std::size_t)num_pairs};
    }

    return {d_of, d_os, d_osc, (std::size_t)num_pairs};
}

