similarity_result_float_t sorensen_all_pairs_similarity(const graph32_t& graph,
                                                        const float* edge_weights,
                                                        const int32_t* vertices,
                                                        std::size_t num_vertices,
                                                        std::optional<std::size_t> topk) {
    static int tag;
